Hello there, I am having trouble creating a Mutation with `django>=2.0`, `django-graphene>=2.0` -> `graphene>=2.0`

The official documentation says a mutation should look like:
```
import graphene

class CreatePerson(graphene.Mutation):
    class Arguments:
        name = graphene.String()

    ok = graphene.Boolean()
    person = graphene.Field(lambda: Person)

    def mutate(self, info, name):
        person = Person(name=name)
        ok = True
        return CreatePerson(person=person, ok=ok)
````

So I created a mutation like:
```
class InvitationType(DjangoObjectType): # resolves to ObjectType
    class Meta:
        model = Invitation

class CreateInvitation(graphene.Mutation):
    class Arguments:
        email = graphene.String(required=True)

    invitation = graphene.Field(InvitationType)

    def mutate(self, info, email):
        invite = Invitation.objects.create(
            creator=info.context.user,
            email=email
        )

        return CreateInvitation(invitation=invite)
